class Solution:
    def largestMultipleOfThree(self, digits) -> str:
        from itertools import combinations
        digits_sorted = sorted(digits, reverse=True)
        n = len(digits_sorted)
        # brute force: try dropping 0, 1, 2 digits (fewest drops first for largest result)
        for drop in range(n + 1):
            for combo in combinations(range(n), drop):
                remaining = [digits_sorted[i] for i in range(n) if i not in combo]
                if sum(remaining) % 3 == 0:
                    remaining.sort(reverse=True)
                    s = ''.join(map(str, remaining))
                    if not s:
                        continue
                    if s[0] == '0':
                        return '0'
                    return s
        return ''

