class Solution:
    def largestMultipleOfThree(self, digits) -> str:
        digits.sort(reverse=True)
        total = sum(digits)
        rem = total % 3
        if rem == 0:
            pass
        else:
            # collect indices by their digit % 3 value
            by_rem = {1: [], 2: []}
            for i, d in enumerate(digits):
                r = d % 3
                if r in by_rem:
                    by_rem[r].append(i)
            # sort each bucket ascending by digit value (remove smallest first)
            for r in by_rem:
                by_rem[r].sort(key=lambda i: digits[i])
            to_remove = set()
            if rem == 1:
                if by_rem[1]:
                    to_remove = {by_rem[1][0]}
                else:
                    to_remove = set(by_rem[2][:2])
            else:  # rem == 2
                if by_rem[2]:
                    to_remove = {by_rem[2][0]}
                else:
                    to_remove = set(by_rem[1][:2])
            digits = [d for i, d in enumerate(digits) if i not in to_remove]
        if not digits:
            return ''
        digits.sort(reverse=True)
        if digits[0] == 0:
            return '0'
        return ''.join(map(str, digits))

