var largestMultipleOfThree = function(digits) {
    digits.sort((a, b) => b - a);
    const total = digits.reduce((s, d) => s + d, 0);
    let rem = total % 3;
    if (rem !== 0) {
        const byRem = {1: [], 2: []};
        for (let i = 0; i < digits.length; i++) {
            const r = digits[i] % 3;
            if (r === 1 || r === 2) byRem[r].push(i);
        }
        for (const r of [1, 2]) byRem[r].sort((a, b) => digits[a] - digits[b]);
        let toRemove = new Set();
        if (rem === 1) {
            if (byRem[1].length) toRemove.add(byRem[1][0]);
            else { toRemove.add(byRem[2][0]); toRemove.add(byRem[2][1]); }
        } else {
            if (byRem[2].length) toRemove.add(byRem[2][0]);
            else { toRemove.add(byRem[1][0]); toRemove.add(byRem[1][1]); }
        }
        digits = digits.filter((_, i) => !toRemove.has(i));
    }
    if (!digits.length) return '';
    digits.sort((a, b) => b - a);
    if (digits[0] === 0) return '0';
    return digits.join('');
};
